import (
	"fmt"
	"strings"
)

// formatNumberPart returns the formatted string for a single number when includeFormatting is true.
// Positive numbers are rendered as "%d,"; negative as "(%d),".
func formatNumberPart(n int, includeFormatting bool) string {
	if !includeFormatting {
		return ""
	}
	if n > 0 {
		return fmt.Sprintf("%d,", n)
	}
	return fmt.Sprintf("(%d),", n)
}

// SumAndFormatIntegers sums all non-zero elements (positive added, negative subtracted from sum).
// If includeFormatting is true, builds a comma-separated string with negatives in parentheses.
// label, if non-empty, is prepended to that string. Returns an error when the sum is zero.
func SumAndFormatIntegers(numbers []int, label string, includeFormatting bool) (sum int, formatted string, err error) {
	var sb strings.Builder
	for _, n := range numbers {
		if n > 0 {
			sum += n
			sb.WriteString(formatNumberPart(n, includeFormatting))
		} else if n < 0 {
			sum -= n
			sb.WriteString(formatNumberPart(n, includeFormatting))
		}
	}
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", label)
	}
	formatted = sb.String()
	if label != "" {
		formatted = label + ": " + formatted
	}
	return sum, formatted, nil
}

func sumAndFormat(values []int, prefix string, formatDetail bool) (int, string, error) {
	var sum int
	var parts []string
	for _, v := range values {
		sum += v
		if formatDetail {
			if v > 0 {
				parts = append(parts, fmt.Sprintf("%d", v))
			} else if v < 0 {
				parts = append(parts, fmt.Sprintf("(%d)", v))
			}
		}
	}
	if sum == 0 {
		return 0, "", fmt.Errorf("empty result for %s", prefix)
	}
	s := ""
	if len(parts) > 0 {
		s = strings.Join(parts, ",") + ","
	}
	if prefix != "" {
		s = prefix + ": " + s
	}
	return sum, s, nil
}
